<template><section class="page"><div class="panel"><el-table :data="rows" v-loading="loading"><el-table-column prop="tracking_no" label="运单号"/><el-table-column prop="anomaly_type" label="异常类型"/><el-table-column prop="severity" label="严重级别"/><el-table-column prop="rule_code" label="规则"/><el-table-column prop="status" label="状态"/><el-table-column prop="description" label="描述"/><el-table-column label="操作"><template #default="s"><el-button size="small" @click="resolve(s.row.id)">标记解决</el-button></template></el-table-column></el-table></div></section></template><script setup lang="ts">import { onMounted, ref } from 'vue'; import { http } from '../api/http'; const rows=ref<any[]>([]); const loading=ref(false); async function load(){loading.value=true; try{rows.value=await http.get('/anomalies')} finally{loading.value=false}} async function resolve(id:number){await http.patch('/anomalies/'+id,{status:'RESOLVED',note:'demo-operator 已处理'}); await load()} onMounted(load)</script>
